// Some portions generated by Claude Code
package org.eclipse.rdf4j.sail.lmdb;

import static org.assertj.core.api.Assertions.assertThat;

import java.io.File;
import java.util.List;

import org.eclipse.rdf4j.model.ValueFactory;
import org.eclipse.rdf4j.query.BindingSet;
import org.eclipse.rdf4j.query.QueryResults;
import org.eclipse.rdf4j.repository.sail.SailRepository;
import org.eclipse.rdf4j.repository.sail.SailRepositoryConnection;
import org.eclipse.rdf4j.sail.lmdb.config.LmdbStoreConfig;
import org.junit.jupiter.api.AfterEach;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.io.TempDir;

/**
 * Regression tests for SPARQL three-valued filter logic on the native LMDB aggregate path: a type error (e.g. a
 * comparison against an unbound OPTIONAL variable) must propagate through negation and drop the row, it must not
 * collapse to false before the negation is applied.
 */
public class LmdbNativeAggregateFilterSemanticsTest {

	private static final String EX = "http://example.com/";

	@TempDir
	File dataDir;

	private SailRepository repository;

	@BeforeEach
	public void setUp() {
		repository = new SailRepository(new LmdbStore(dataDir, new LmdbStoreConfig("spoc,posc")));
		try (SailRepositoryConnection conn = repository.getConnection()) {
			ValueFactory vf = conn.getValueFactory();
			// :a has a name, :b does not
			conn.add(vf.createIRI(EX, "a"), vf.createIRI(EX, "p"), vf.createLiteral("1"));
			conn.add(vf.createIRI(EX, "a"), vf.createIRI(EX, "name"), vf.createLiteral("n1"));
			conn.add(vf.createIRI(EX, "b"), vf.createIRI(EX, "p"), vf.createLiteral("2"));
		}
	}

	@AfterEach
	public void tearDown() {
		repository.shutDown();
	}

	private long countResult(String query) {
		try (SailRepositoryConnection conn = repository.getConnection()) {
			List<BindingSet> result = QueryResults.asList(conn.prepareTupleQuery(query).evaluate());
			assertThat(result).hasSize(1);
			return ((org.eclipse.rdf4j.model.Literal) result.get(0).getValue("c")).longValue();
		}
	}

	@Test
	public void negatedEqualityOverUnboundOptionalVarDropsRow() {
		// for :b, ?name is unbound: (?name = "zzz") is a type error, !error is still an error and
		// the row must be dropped, so only :a is counted
		long count = countResult("SELECT (COUNT(?s) AS ?c) WHERE {\n"
				+ "  ?s <" + EX + "p> ?o .\n"
				+ "  OPTIONAL { ?s <" + EX + "name> ?name }\n"
				+ "  FILTER(!(?name = \"zzz\"))\n"
				+ "}");
		assertThat(count).isEqualTo(1);
	}

	@Test
	public void notInOverUnboundOptionalVarDropsRow() {
		long count = countResult("SELECT (COUNT(?s) AS ?c) WHERE {\n"
				+ "  ?s <" + EX + "p> ?o .\n"
				+ "  OPTIONAL { ?s <" + EX + "name> ?name }\n"
				+ "  FILTER(?name NOT IN (\"zzz\"))\n"
				+ "}");
		assertThat(count).isEqualTo(1);
	}

	@Test
	public void negatedDisjunctionOverUnboundOptionalVarDropsRow() {
		long count = countResult("SELECT (COUNT(?s) AS ?c) WHERE {\n"
				+ "  ?s <" + EX + "p> ?o .\n"
				+ "  OPTIONAL { ?s <" + EX + "name> ?name }\n"
				+ "  FILTER(!(?name = \"zzz\" || ?name = \"yyy\"))\n"
				+ "}");
		assertThat(count).isEqualTo(1);
	}

	@Test
	public void negatedExistsStaysCorrect() {
		// NOT EXISTS never produces a type error and must keep its usual semantics: only :b has no name
		long count = countResult("SELECT (COUNT(?s) AS ?c) WHERE {\n"
				+ "  ?s <" + EX + "p> ?o .\n"
				+ "  FILTER(!EXISTS { ?s <" + EX + "name> ?name })\n"
				+ "}");
		assertThat(count).isEqualTo(1);
	}

	@Test
	public void positiveComparisonOverUnboundOptionalVarDropsRow() {
		// sanity: without negation both engines agree, the error row is dropped either way
		long count = countResult("SELECT (COUNT(?s) AS ?c) WHERE {\n"
				+ "  ?s <" + EX + "p> ?o .\n"
				+ "  OPTIONAL { ?s <" + EX + "name> ?name }\n"
				+ "  FILTER(?name = \"n1\")\n"
				+ "}");
		assertThat(count).isEqualTo(1);
	}

	@Test
	public void constantErrorConditionYieldsEmptyAggregate() {
		// 'not a number' + 1 always raises a type error, so the condition can never accept a row;
		// the generic engine folds a condition that fails to precompile into constant-false
		// (FilterIterator.supply) instead of surfacing the error at evaluate() time
		long count = countResult("SELECT (COUNT(?s) AS ?c) WHERE {\n"
				+ "  ?s <" + EX + "p> ?o .\n"
				+ "  FILTER('not a number' + 1 = ?o)\n"
				+ "}");
		assertThat(count).isEqualTo(0);
	}

	@Test
	public void negatedConstantErrorConditionYieldsEmptyAggregate() {
		// the error raised by comparing incompatible constant literals survives the negation, so
		// the filter is still constant-false, not constant-true
		long count = countResult("SELECT (COUNT(?s) AS ?c) WHERE {\n"
				+ "  ?s <" + EX + "p> ?o .\n"
				+ "  FILTER(!(\"2002\"^^<http://www.w3.org/2001/XMLSchema#string>"
				+ " = \"2007\"^^<http://www.w3.org/2001/XMLSchema#gYear>))\n"
				+ "}");
		assertThat(count).isEqualTo(0);
	}
}
